def trimmed_mean(nums):
    if not nums:
        return None
    nums.sort()
    n = len(nums)
    median_index = (n - 1) // 2
    min_index, max_index = median_index, n - median_index - 1
    if len(nums) % 2 == 0:
        mid1, mid2 = nums[median_index], nums[median_index + 1]
    else:
        mid1 = nums[median_index]
    trimmed_list = [n for n in nums if n not in (min(nums), max(nums))]
    trimmed_sum = sum(trimmed_list)
    return (trimmed_sum - min(mid1, mid2) - max(mid1, mid2)) / (len(trimmed_list) - 1)
